// Parse & Normalize Actions (AG1-V3 GPT5.2)
// Input: $json.output (string/object/array)
// Output: $json.actions (array) + $json.agentDecision

function isFxSymbol(sym) {
  const s = String(sym || '').trim().toUpperCase();
  return s.startsWith('FX:') || s.endsWith('=X');
}

function stripFences(raw) {
  let t = String(raw || '').trim();
  t = t.replace(/^\s*```(?:json)?\s*/i, '');
  t = t.replace(/\s*```\s*$/i, '');
  return t.trim();
}

function extractJsonBlock(text) {
  const t = String(text || '');
  const iArr = t.indexOf('[');
  const jArr = t.lastIndexOf(']');
  if (iArr !== -1 && jArr !== -1 && jArr > iArr) return t.slice(iArr, jArr + 1);

  const iObj = t.indexOf('{');
  const jObj = t.lastIndexOf('}');
  if (iObj !== -1 && jObj !== -1 && jObj > iObj) return t.slice(iObj, jObj + 1);

  return '';
}

function toIntOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  if (Number.isFinite(n)) return Math.trunc(n);
  return null;
}

function toNumOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function normalizeDependencies(dep) {
  const base = {
    needPrice: false,
    needNote: false,
    needNews: false,
    needTechnical: false,
    needConsensus: false,
  };

  if (Array.isArray(dep)) {
    const aliases = {
      needprice: 'needPrice',
      price: 'needPrice',
      neednote: 'needNote',
      note: 'needNote',
      neednews: 'needNews',
      news: 'needNews',
      needtechnical: 'needTechnical',
      technical: 'needTechnical',
      needconsensus: 'needConsensus',
      consensus: 'needConsensus',
    };
    for (const s of dep) {
      const key = String(s || '').trim();
      const norm = aliases[key.toLowerCase()] || key;
      if (norm in base) base[norm] = true;
    }
    return base;
  }

  if (dep && typeof dep === 'object') {
    return {
      needPrice: Boolean(dep.needPrice ?? false),
      needNote: Boolean(dep.needNote ?? false),
      needNews: Boolean(dep.needNews ?? false),
      needTechnical: Boolean(dep.needTechnical ?? false),
      needConsensus: Boolean(dep.needConsensus ?? false),
    };
  }

  return base;
}

function normalizeAssetClass(assetClass, symbol) {
  const ac = (assetClass ?? '').toString().trim().toUpperCase();
  if (ac === 'FOREX' || ac === 'CURRENCY') return 'FX';
  if (ac === 'FX' || ac === 'EQUITY' || ac === 'CRYPTO') return ac;
  return isFxSymbol(symbol) ? 'FX' : 'EQUITY';
}

function ensureEntryPlan(ep) {
  const o = (ep && typeof ep === 'object') ? ep : {};
  return {
    orderType: o.orderType ?? null,
    limitPrice: toNumOrNull(o.limitPrice),
    timeInForce: o.timeInForce ?? null,
  };
}

function ensureRiskPlan(rp) {
  const o = (rp && typeof rp === 'object') ? rp : {};
  return {
    stopLossPct: toNumOrNull(o.stopLossPct),
    takeProfitPct: toNumOrNull(o.takeProfitPct),
    maxLossEUR: toNumOrNull(o.maxLossEUR),
  };
}

function normalizeAction(a, idx, warnings) {
  const inObj = (a && typeof a === 'object') ? a : {};
  const sym = String(inObj.symbol ?? inObj.symbol_internal ?? inObj.symbol_yahoo ?? '').trim().toUpperCase();
  if (!sym) {
    warnings.push(`action[${idx}] skipped: missing symbol`);
    return null;
  }

  let act = String(inObj.action ?? inObj.signal ?? '').trim().toUpperCase();
  if (act === 'BUY') act = 'OPEN';
  if (act === 'SELL') act = 'CLOSE';

  const allowed = new Set(['OPEN','INCREASE','DECREASE','CLOSE','HOLD','WATCH','PROPOSE_OPEN','PROPOSE_CLOSE']);
  if (!allowed.has(act)) {
    warnings.push(`action[${idx}] invalid action '${act}' -> WATCH`);
    act = 'WATCH';
  }

  return {
    symbol: sym,
    assetClass: normalizeAssetClass(inObj.assetClass, sym),
    symbol_internal: inObj.symbol_internal ?? null,
    symbol_yahoo: inObj.symbol_yahoo ?? null,
    action: act,
    priority: Number.isFinite(Number(inObj.priority)) ? Math.trunc(Number(inObj.priority)) : 3,
    confidence: (inObj.confidence === null || inObj.confidence === undefined) ? null : toIntOrNull(inObj.confidence),
    horizonDays: (inObj.horizonDays === null || inObj.horizonDays === undefined) ? null : toIntOrNull(inObj.horizonDays),
    targetWeightPct: toNumOrNull(inObj.targetWeightPct),
    targetQty: toNumOrNull(inObj.targetQty),
    rationale: String(inObj.rationale ?? '').trim(),
    entryPlan: ensureEntryPlan(inObj.entryPlan),
    riskPlan: ensureRiskPlan(inObj.riskPlan),
    dependencies: normalizeDependencies(inObj.dependencies),
    execution_required: (inObj.execution_required === null || inObj.execution_required === undefined) ? null : Boolean(inObj.execution_required),
    needs_risk_approval: (inObj.needs_risk_approval === null || inObj.needs_risk_approval === undefined) ? null : Boolean(inObj.needs_risk_approval),
    proposed_position: (inObj.proposed_position && typeof inObj.proposed_position === 'object')
      ? {
          direction: inObj.proposed_position.direction ?? null,
          conviction: toNumOrNull(inObj.proposed_position.conviction),
        }
      : null,
    nextReviewDays: Number.isFinite(Number(inObj.nextReviewDays)) ? Math.trunc(Number(inObj.nextReviewDays)) : 3,
  };
}

function parsePayload(jsonInput) {
  const warnings = [];
  const rawCandidates = [
    jsonInput?.output,
    jsonInput?.text,
    jsonInput?.response,
    jsonInput?.answer,
    jsonInput?.output?.text,
    (Array.isArray(jsonInput?.output) ? jsonInput.output?.[0]?.content?.[0]?.text : null),
  ];

  let parsedRoot = null;
  let parseStatus = 'MISSING_INPUT';
  let outputRawSanitized = null;
  let outputJsonBlock = null;

  const outputVal = jsonInput?.output;
  if (Array.isArray(outputVal)) {
    parsedRoot = outputVal;
    parseStatus = 'OK_OUTPUT_ARRAY';
  } else if (outputVal && typeof outputVal === 'object') {
    parsedRoot = outputVal;
    parseStatus = 'OK_OUTPUT_OBJECT';
  }

  if (parsedRoot === null) {
    const raw = rawCandidates.find((x) => typeof x === 'string' && String(x).trim().length > 0) || '';
    if (raw) {
      outputRawSanitized = stripFences(raw);
      outputJsonBlock = extractJsonBlock(outputRawSanitized);
      if (outputJsonBlock) {
        try {
          parsedRoot = JSON.parse(outputJsonBlock);
          parseStatus = 'OK_PARSED_TEXT';
        } catch (e) {
          parseStatus = 'PARSE_ERROR';
          warnings.push(`JSON.parse failed: ${String(e?.message || e)}`);
        }
      } else {
        parseStatus = 'NO_JSON_BLOCK';
        warnings.push('No JSON delimiters found in output text');
      }
    }
  }

  let sourceActions = [];
  let baseObj = {};

  if (Array.isArray(parsedRoot)) {
    sourceActions = parsedRoot;
  } else if (parsedRoot && typeof parsedRoot === 'object') {
    baseObj = parsedRoot;
    if (Array.isArray(parsedRoot.actions)) {
      sourceActions = parsedRoot.actions;
    } else {
      sourceActions = [parsedRoot];
      warnings.push('Parsed object has no actions[]; treated as single action object');
    }
  }

  const normalized = [];
  for (let i = 0; i < sourceActions.length; i += 1) {
    const n = normalizeAction(sourceActions[i], i, warnings);
    if (n) normalized.push(n);
  }

  const agentDecision = {
    ...(baseObj && typeof baseObj === 'object' && !Array.isArray(baseObj) ? baseObj : {}),
    actions: normalized,
    dataCaveats: Array.isArray(baseObj?.dataCaveats) ? baseObj.dataCaveats : [],
    backfillRequests: Array.isArray(baseObj?.backfillRequests) ? baseObj.backfillRequests : [],
    _parseStatus: parseStatus,
    _parseWarnings: warnings,
  };

  return {
    outputRawSanitized,
    outputJsonBlock,
    actions: normalized,
    agentDecision,
  };
}

const parsed = parsePayload($json || {});

return [{
  json: {
    ...($json || {}),
    output_raw_sanitized: parsed.outputRawSanitized,
    output_json_block: parsed.outputJsonBlock,
    actions: parsed.actions,
    agentDecision: parsed.agentDecision,
    output: parsed.agentDecision,
  }
}];
